import React, { useState, useMemo, useRef } from 'react';
import { useLiteralnessDispatch, useLiteralnessState } from '../../contexts/LiteralnessContext';
import { useQuestionDispatch } from '../../contexts/QuestionContext';
import { useFlashcardDispatch } from '../../contexts/FlashcardContext';
import { useSettings } from '../../contexts/SettingsContext';
import { LiteralnessCard, Question, Flashcard, LawContentType } from '../../types';
import * as srs from '../../services/srsService';
import { parseLitRefText, ParseDiagnosis, ParseIssue } from '../../services/import/litRefParser';
import { nucleusRepo } from '../../services/repositoryService';
import { 
    CheckCircleIcon, XMarkIcon, CloudIcon, ChevronLeftIcon, 
    ExclamationTriangleIcon, BoltIcon, TrashIcon, ArrowPathIcon
} from '../icons';

interface ImportLiteralnessProps {
    type?: LawContentType;
    onBack?: () => void;
    forcedLawId?: string | null;
}

const ImportLiteralness: React.FC<ImportLiteralnessProps> = ({ type = 'LAW_DRY', onBack }) => {
    const { addBatchCards } = useLiteralnessDispatch();
    const { addBatchQuestions } = useQuestionDispatch();
    const { addBatchFlashcards } = useFlashcardDispatch();
    const { settings } = useSettings();
    const allCards = useLiteralnessState();

    const [text, setText] = useState('');
    const [diagnosis, setDiagnosis] = useState<ParseDiagnosis | null>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const textareaRef = useRef<HTMLTextAreaElement>(null);

    // --- ACTIONS ---

    const handleAnalyze = () => {
        if (!text.trim()) return;
        setIsProcessing(true);
        setTimeout(() => {
            const batchId = `BATCH_${Date.now()}`;
            const result = parseLitRefText(text, settings, batchId);
            setDiagnosis(result);
            setIsProcessing(false);
        }, 100); // Async simulation for UI response
    };

    const handleImport = async (mode: 'OVERWRITE' | 'MERGE' | 'SKIP') => {
        if (!diagnosis || !diagnosis.isValid) return;
        setIsProcessing(true);

        try {
            const batch = {
                cards: diagnosis.parsedData.nuclei,
                questions: diagnosis.parsedData.questions,
                flashcards: diagnosis.parsedData.flashcards
            };

            // Process based on mode (Logic delegated to Repository to keep UI clean)
            // Note: Repository handles "Overwrite" by replacing children. 
            // "Skip" logic is: filter out existing cards from batch before saving.

            if (mode === 'SKIP') {
                const existingIds = new Set(allCards.map(c => c.id));
                batch.cards = batch.cards.filter(c => !existingIds.has(c.id));
                // We also filter children to only include those for new cards
                // (Assuming Skip means "Don't touch existing articles at all")
                const newCardIds = new Set(batch.cards.map(c => c.id));
                batch.questions = batch.questions.filter(q => newCardIds.has(srs.canonicalizeLitRef(q.lawRef)));
                batch.flashcards = batch.flashcards.filter(f => newCardIds.has(srs.resolveLitRef(f)));
            }

            // Use Repository Service for Robust Save (Transactional-ish)
            await nucleusRepo.saveImportBatch(batch);

            // Refresh Contexts (The providers effectively reload from DB or we push directly)
            // For now, we push to dispatchers to update UI state immediately
            addBatchCards(batch.cards);
            addBatchQuestions(batch.questions, mode === 'OVERWRITE' ? 'OVERWRITE' : 'MERGE'); 
            addBatchFlashcards(batch.flashcards);

            alert(`Importação concluída (${mode})!\n${batch.cards.length} Artigos processados.`);
            setDiagnosis(null);
            setText('');

        } catch (e: any) {
            alert(`Erro ao salvar: ${e.message}`);
        } finally {
            setIsProcessing(false);
        }
    };

    // --- UI HELPERS ---

    const highlightError = (line: number) => {
        if (textareaRef.current) {
            const lines = text.split('\n');
            let start = 0;
            for (let i = 0; i < line - 1; i++) {
                start += lines[i].length + 1; // +1 for newline
            }
            const end = start + lines[line - 1].length;

            textareaRef.current.focus();
            textareaRef.current.setSelectionRange(start, end);
            textareaRef.current.scrollTop = start / 3; // Approx scroll
        }
    };

    // --- RENDER ---

    return (
        <div className="max-w-6xl mx-auto space-y-6 pb-24 animate-fade-in px-4 h-full flex flex-col">

            {/* Header */}
            <div className="flex justify-between items-center bg-slate-900/80 p-4 rounded-2xl border border-white/10 backdrop-blur shrink-0">
                <div className="flex items-center gap-3">
                    <CloudIcon className="text-sky-400 w-8 h-8" />
                    <div>
                        <h3 className="text-xl font-black text-white italic tracking-tighter">Importador Lei Seca</h3>
                        <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">Parser v2.0 • Blocos • Validação</p>
                    </div>
                </div>
                {onBack && <button onClick={onBack} className="p-2 bg-white/5 rounded-full hover:bg-white/10 text-slate-400 hover:text-white"><XMarkIcon className="w-5 h-5"/></button>}
            </div>

            <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-6 min-h-0">

                {/* LEFT: Editor */}
                <div className="flex flex-col gap-4 h-full">
                    <div className="flex-1 bg-slate-900 border border-white/10 rounded-2xl p-1 relative">
                        <textarea 
                            ref={textareaRef}
                            value={text} 
                            onChange={(e) => { setText(e.target.value); if(diagnosis) setDiagnosis(null); }} 
                            className="w-full h-full bg-transparent p-4 text-xs font-mono text-sky-100 outline-none resize-none leading-relaxed custom-scrollbar whitespace-pre" 
                            placeholder="Cole aqui seu conteúdo (LIT_REF: ...)"
                            spellCheck={false}
                        />
                        {/* Line Numbers Overlay could go here if needed */}
                    </div>
                    <div className="flex justify-between items-center shrink-0">
                         <button onClick={() => setText('')} className="text-slate-500 hover:text-rose-500 p-2"><TrashIcon className="w-5 h-5"/></button>
                         <button 
                            onClick={handleAnalyze} 
                            disabled={!text.trim() || isProcessing}
                            className="bg-sky-600 hover:bg-sky-500 text-white font-black px-8 py-3 rounded-xl shadow-lg transition-all active:scale-95 flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                         >
                             {isProcessing ? <ArrowPathIcon className="w-4 h-4 animate-spin"/> : <BoltIcon className="w-4 h-4"/>}
                             ANALISAR TEXTO
                         </button>
                    </div>
                </div>

                {/* RIGHT: Diagnostics & Actions */}
                <div className="flex flex-col gap-4 h-full overflow-hidden">
                    {diagnosis ? (
                        <div className="flex flex-col h-full bg-slate-900/50 border border-white/10 rounded-2xl overflow-hidden">
                            {/* Stats Header */}
                            <div className="p-4 border-b border-white/5 bg-slate-900/80 grid grid-cols-3 gap-2 text-center shrink-0">
                                <div className="p-2 bg-white/5 rounded-lg"><span className="block text-xl font-black text-white">{diagnosis.stats.articles}</span><span className="text-[8px] uppercase text-slate-500 font-bold">Artigos</span></div>
                                <div className="p-2 bg-white/5 rounded-lg"><span className="block text-xl font-black text-sky-400">{diagnosis.stats.questions}</span><span className="text-[8px] uppercase text-slate-500 font-bold">Questões</span></div>
                                <div className="p-2 bg-white/5 rounded-lg"><span className="block text-xl font-black text-emerald-400">{diagnosis.stats.flashcards + diagnosis.stats.pairs}</span><span className="text-[8px] uppercase text-slate-500 font-bold">Cards</span></div>
                            </div>

                            {/* Issues List */}
                            <div className="flex-1 overflow-y-auto custom-scrollbar p-4 space-y-2">
                                {diagnosis.issues.length === 0 ? (
                                    <div className="text-center py-10 opacity-50">
                                        <CheckCircleIcon className="w-12 h-12 text-emerald-500 mx-auto mb-2"/>
                                        <p className="text-sm font-bold text-emerald-400">Nenhum erro encontrado.</p>
                                    </div>
                                ) : (
                                    diagnosis.issues.map((issue, idx) => (
                                        <div 
                                            key={idx} 
                                            onClick={() => highlightError(issue.line)}
                                            className={`p-3 rounded-xl border cursor-pointer hover:bg-white/5 transition-all ${issue.severity === 'ERROR' ? 'bg-rose-500/10 border-rose-500/30' : 'bg-amber-500/10 border-amber-500/30'}`}
                                        >
                                            <div className="flex justify-between items-center mb-1">
                                                <span className={`text-[9px] font-black uppercase px-1.5 py-0.5 rounded ${issue.severity === 'ERROR' ? 'bg-rose-500 text-white' : 'bg-amber-500 text-black'}`}>
                                                    {issue.severity}
                                                </span>
                                                <span className="text-[10px] font-mono text-slate-500">Linha {issue.line}</span>
                                            </div>
                                            <p className="text-xs text-white font-medium mb-1"><span className="opacity-50">[{issue.block}]</span> {issue.message}</p>
                                            <p className="text-[10px] text-sky-400 font-bold">💡 {issue.suggestion}</p>
                                        </div>
                                    ))
                                )}
                            </div>

                            {/* Action Buttons */}
                            <div className="p-4 border-t border-white/5 bg-slate-900/80 shrink-0">
                                {diagnosis.isValid ? (
                                    <div className="grid grid-cols-3 gap-2">
                                        <button onClick={() => handleImport('SKIP')} className="py-3 rounded-xl border border-white/10 hover:bg-white/5 text-slate-400 font-bold text-[10px] uppercase">Ignorar Existentes</button>
                                        <button onClick={() => handleImport('MERGE')} className="py-3 rounded-xl bg-sky-600 hover:bg-sky-500 text-white font-bold text-[10px] uppercase shadow-lg">Mesclar (Update)</button>
                                        <button onClick={() => handleImport('OVERWRITE')} className="py-3 rounded-xl bg-amber-600 hover:bg-amber-500 text-white font-black text-[10px] uppercase shadow-lg">Sobrescrever</button>
                                    </div>
                                ) : (
                                    <div className="bg-rose-500/10 border border-rose-500/20 p-3 rounded-xl text-center">
                                        <p className="text-xs font-bold text-rose-400">Corrija os erros acima para importar.</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center text-center opacity-30 border-2 border-dashed border-slate-700 rounded-2xl">
                            <BoltIcon className="w-16 h-16 mb-4 text-slate-500"/>
                            <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">Aguardando Análise</p>
                        </div>
                    )}
                </div>

            </div>
        </div>
    );
};

export default ImportLiteralness;

import { LiteralnessCard, Question, Flashcard, AppSettings } from '../../types';
import * as srs from '../srsService';
import * as idGen from '../idGenerator';
import { buildReadingSteps } from '../readingParser';
import { sanitizeOptionText } from '../questionParser';
import { parseDiagnosisMap } from '../../utils/feedbackFormatters';
import { normalizeDiscipline } from '../taxonomyService';

// --- TYPES ---

export type ParseSeverity = 'ERROR' | 'WARNING';

export interface ParseIssue {
    line: number;
    severity: ParseSeverity;
    block: string;
    field: string;
    message: string;
    suggestion: string;
}

export interface ParseDiagnosis {
    isValid: boolean;
    issues: ParseIssue[];
    stats: {
        articles: number;
        questions: number;
        flashcards: number;
        pairs: number;
        gaps: number;
    };
    parsedData: {
        nuclei: any[];
        questions: any[];
        flashcards: any[];
        gaps: any[];
    }
}

// --- CONSTANTS ---

const STATES = {
    NONE: 'NONE',
    HEADER: 'HEADER',
    QUESTION: 'QUESTION',
    FLASHCARD: 'FLASHCARD',
    PAIR: 'PAIR'
};

const REQUIRED_HEADER_FIELDS = ['LIT_REF', 'LAW_ID', 'ARTICLE'];
const REQUIRED_QUESTION_FIELDS = ['Q_TEXT', 'CORRECT'];
const OPTION_KEYS = ['A', 'B', 'C', 'D', 'E'];

// --- HELPERS ---

const normalizeLine = (line: string) => line.replace(/^\uFEFF/, '').replace(/\r$/, '');

const extractKey = (line: string): { key: string, value: string } | null => {
    const match = line.match(/^([A-Z0-9_]+)(?:_\d+)?\s*[:=]\s*(.*)$/);
    if (match) {
        return { key: match[1].toUpperCase(), value: match[2].trim() };
    }
    return null;
};

// --- MAIN PARSER (State Machine) ---

export const parseLitRefText = (text: string, settings: AppSettings, batchId: string): ParseDiagnosis => {
    const lines = text.split('\n');
    const issues: ParseIssue[] = [];

    // Output Containers
    const nuclei: any[] = [];
    const questions: any[] = [];
    const flashcards: any[] = []; // Includes pairs

    // State Variables
    let state = STATES.NONE;
    let currentObj: any = {};
    let currentLineStart = 0;

    // Accumulator for multiline values
    let lastKey: string | null = null;

    // Context Tracking (for linking children)
    let activeLitRef: string | null = null;
    let activeLawId: string = 'GERAL';
    let activeTopic: string = 'Geral';
    let activeArticle: string = '';

    const flushObject = () => {
        if (!currentObj) return;

        if (state === STATES.HEADER) {
            // Validate Header
            if (!currentObj.LIT_REF) {
                issues.push({ line: currentLineStart, severity: 'ERROR', block: 'HEADER', field: 'LIT_REF', message: 'Artigo sem LIT_REF.', suggestion: 'Adicione "LIT_REF: CODIGO_ART_XX"' });
            } else {
                activeLitRef = srs.canonicalizeLitRef(currentObj.LIT_REF);
                activeLawId = currentObj.LAW_ID || activeLawId;
                activeTopic = currentObj.TOPIC || activeTopic;
                activeArticle = currentObj.ARTICLE || activeLitRef;

                // Push to nuclei
                nuclei.push({
                    ...currentObj,
                    id: activeLitRef,
                    lawId: activeLawId,
                    article: activeArticle,
                    topic: activeTopic,
                    importBatchId: batchId
                });
            }
        } else if (state === STATES.QUESTION) {
            if (!activeLitRef) {
                issues.push({ line: currentLineStart, severity: 'ERROR', block: 'QUESTION', field: 'CONTEXT', message: 'Questão fora de um artigo (Orphan).', suggestion: 'Mova esta questão para baixo de um LIT_REF.' });
                return;
            }

            const qRef = currentObj.Q_REF || `Q-${Date.now()}-${Math.random()}`;

            // Validate Options & Correct
            const opts: any = {};
            let hasEmptyOption = false;

            OPTION_KEYS.forEach(k => {
                // Check raw keys A, B... or OPT_A, OPT_B...
                const val = currentObj[k] || currentObj[`OPT_${k}`];
                if (val) {
                    opts[k] = sanitizeOptionText(val);
                } else if (currentObj[k] === '') { // Explicitly empty
                     hasEmptyOption = true;
                     issues.push({ line: currentLineStart, severity: 'ERROR', block: qRef, field: k, message: `Alternativa ${k} está vazia.`, suggestion: 'Preencha o texto ou remova a linha.' });
                }
            });

            // Validate Correct
            const correct = (currentObj.CORRECT || currentObj.ANSWER || '').trim().toUpperCase().charAt(0);
            if (!correct) {
                issues.push({ line: currentLineStart, severity: 'ERROR', block: qRef, field: 'CORRECT', message: 'Gabarito ausente.', suggestion: 'Adicione "CORRECT: X"' });
            } else if (!opts[correct] && !currentObj.TYPE?.includes('C/E')) {
                 issues.push({ line: currentLineStart, severity: 'ERROR', block: qRef, field: 'CORRECT', message: `Gabarito ${correct} aponta para opção inexistente.`, suggestion: `Verifique se a opção ${correct} existe.` });
            }

            questions.push({
                ...currentObj,
                id: idGen.generateQuestionKey(qRef),
                questionRef: qRef,
                questionText: currentObj.Q_TEXT || currentObj.QUESTION_TEXT || '',
                correctAnswer: correct,
                options: opts,
                lawRef: activeLitRef,
                subject: activeLawId,
                topic: activeTopic
            });

        } else if (state === STATES.FLASHCARD || state === STATES.PAIR) {
             if (!activeLitRef) {
                issues.push({ line: currentLineStart, severity: 'ERROR', block: 'FLASHCARD', field: 'CONTEXT', message: 'Item fora de um artigo.', suggestion: 'Mova para baixo de um LIT_REF.' });
                return;
            }

            const ref = currentObj.FC_REF || currentObj.PAIR_REF || `FC-${Math.random()}`;
            if (!currentObj.FRONT || !currentObj.BACK) {
                 issues.push({ line: currentLineStart, severity: 'ERROR', block: ref, field: 'FRONT/BACK', message: 'Flashcard incompleto.', suggestion: 'Adicione FRONT e BACK.' });
            }

            flashcards.push({
                ...currentObj,
                id: ref,
                front: currentObj.FRONT,
                back: currentObj.BACK,
                discipline: activeLawId,
                topic: activeTopic,
                tags: [activeLitRef, state === STATES.PAIR ? 'pair-match' : 'literalness'],
                litRef: activeLitRef,
                type: state
            });
        }
    };

    // --- LINE ITERATION ---

    for (let i = 0; i < lines.length; i++) {
        const line = normalizeLine(lines[i]).trim();
        const lineNum = i + 1;

        if (!line || line.startsWith('#') || line.startsWith('---')) continue;

        // Detect Block Starters
        if (line.startsWith('LIT_REF:')) {
            flushObject();
            state = STATES.HEADER;
            currentObj = {};
            currentLineStart = lineNum;
            lastKey = null;
        } else if (line.startsWith('Q_REF:')) {
            flushObject();
            state = STATES.QUESTION;
            currentObj = {};
            currentLineStart = lineNum;
            lastKey = null;
        } else if (line.startsWith('FC_REF:')) {
            flushObject();
            state = STATES.FLASHCARD;
            currentObj = {};
            currentLineStart = lineNum;
            lastKey = null;
        } else if (line.startsWith('PAIR_REF:')) {
            flushObject();
            state = STATES.PAIR;
            currentObj = {};
            currentLineStart = lineNum;
            lastKey = null;
        }

        // Parse Key-Value
        const kv = extractKey(line);
        if (kv) {
            // Special handling for Phase 2 indexed keys (PHASE2_LACUNA_01)
            // We strip the suffix for the key name in parsing, but keep full key in object to map later
            currentObj[kv.key] = kv.value;
            lastKey = kv.key;
        } else if (lastKey) {
            // Multiline append
            currentObj[lastKey] += '\n' + line;
        }
    }

    // Flush last object
    flushObject();

    // --- TRANSFORM & COUNT ---

    const finalCards: LiteralnessCard[] = [];
    const finalQuestions: Question[] = [];
    const finalFlashcards: Flashcard[] = [];
    const finalGaps: any[] = []; // Raw gap objects

    const today = srs.todayISO();

    // 1. Process Cards & Gaps
    nuclei.forEach(n => {
        // Extract Gaps from Nucleus fields (PHASE2_LACUNA_XX)
        const cardGaps: any[] = [];
        const gapKeys = Object.keys(n).filter(k => k.startsWith('PHASE2_LACUNA_'));

        gapKeys.forEach(k => {
            const suffix = k.replace('PHASE2_LACUNA_', ''); // e.g. "01"
            const text = n[k];

            // Check placeholders
            const matches = text.match(/\{\{.+?\}\}/g);
            if (!matches) {
                 issues.push({ line: 0, severity: 'ERROR', block: n.id, field: k, message: `Lacuna ${suffix} sem placeholder {{...}}.`, suggestion: 'Marque a resposta com {{ }}' });
            } else if (matches.length > 1) {
                 issues.push({ line: 0, severity: 'ERROR', block: n.id, field: k, message: `Lacuna ${suffix} com múltiplos placeholders.`, suggestion: 'Use apenas um {{...}} por lacuna.' });
            }

            const correctLetter = (n[`PHASE2_CORRECT_${suffix}`] || 'A').trim().toUpperCase();
            if (!OPTION_KEYS.includes(correctLetter)) {
                 issues.push({ line: 0, severity: 'ERROR', block: n.id, field: `PHASE2_CORRECT_${suffix}`, message: `Gabarito ${correctLetter} inválido.`, suggestion: 'Use A, B, C, D ou E.' });
            }

            const opts = {
                A: sanitizeOptionText(n[`PHASE2_OPT_A_${suffix}`]),
                B: sanitizeOptionText(n[`PHASE2_OPT_B_${suffix}`]),
                C: sanitizeOptionText(n[`PHASE2_OPT_C_${suffix}`]),
                D: sanitizeOptionText(n[`PHASE2_OPT_D_${suffix}`]),
                E: sanitizeOptionText(n[`PHASE2_OPT_E_${suffix}`]),
            };

            // Check if correct option exists
            // @ts-ignore
            if (!opts[correctLetter]) {
                 issues.push({ line: 0, severity: 'ERROR', block: n.id, field: `PHASE2_OPT_${correctLetter}_${suffix}`, message: `Opção correta vazia.`, suggestion: 'Preencha a alternativa.' });
            }

            const gapId = idGen.makeDeterministicId(n.id, 'LACUNA', suffix);

            const gapObj = {
                id: gapId,
                litRef: n.id,
                type: 'LACUNA',
                payload: {
                    lacuna_text: text,
                    correct_letter: correctLetter,
                    options: opts
                }
            };
            cardGaps.push({
                 id: gapId,
                 text: text,
                 correct: correctLetter,
                 options: opts,
                 questionRef: `GAP-${suffix}`
            });
            finalGaps.push(gapObj);
        });

        const card: LiteralnessCard = {
            id: n.id,
            lawId: normalizeDiscipline(n.lawId),
            article: n.article,
            topic: n.topic,
            phase1Full: n.PHASE1_FULL || '',
            partsSummary: n.PARTS_SUMMARY || n.RESUMO_POR_PARTES || '',
            keywordsProva: n.KEYWORDS_PROVA || '',
            riscoFcc: n.RISCO_FCC || '',
            gancho: n.GANCHO_MNEMONICO || '',
            storytelling: n.STORYTELLING || '',
            feynmanExplanation: n.FEYNMAN || '',
            createdAt: today, nextReviewDate: today, lastReviewedAt: today, masteryScore: 0, totalAttempts: 0,
            stability: settings.srsV2.S_default_days,
            batteryProgress: 0, progressionLevel: 0, userNotes: '',
            contentType: 'LAW_DRY', importBatchId: batchId,
            extraGaps: cardGaps // Hydrated here for preview
        };
        card.studyFlow = buildReadingSteps(card);
        finalCards.push(card);
    });

    // 2. Process Questions
    questions.forEach(q => {
        const newQ: Question = {
            id: idGen.makeDeterministicId(q.lawRef, 'QUESTION', q.questionRef),
            questionRef: q.questionRef,
            questionText: q.questionText,
            options: q.options,
            correctAnswer: q.correctAnswer,
            subject: normalizeDiscipline(q.subject),
            topic: q.topic,
            lawRef: q.lawRef,
            // ... defaults
            explanation: q.EXPLANATION || '',
            explanationTech: q.EXPLANATION_TECH || '',
            explanationStory: q.EXPLANATION_STORY || '',
            wrongDiagnosis: q.WRONG_DIAGNOSIS || '',
            distractorProfile: parseDiagnosisMap(q.DISTRACTOR_PROFILE),
            wrongDiagnosisMap: parseDiagnosisMap(q.WRONG_DIAGNOSIS_MAP),
            guiaTrapscan: q.GUIA_TRAPSCAN || '',
            keyDistinction: q.KEY_DISTINCTION || '',
            anchorText: q.ANCHOR_TEXT || '',

            importBatchId: batchId,
            createdAt: today, nextReviewDate: today, totalAttempts: 0, masteryScore: 0,
            stability: settings.srsV2.S_default_days, attemptHistory: [],
            questionType: q.TYPE || 'Literalidade',
            hotTopic: !!q.HOT, isCritical: !!q.CRIT, isFundamental: !!q.FUND,
            lastAttemptDate: '', errorCount: 0, timeSec: 0, selfEvalLevel: 0,
            willFallExam: false, srsStage: 0, correctStreak: 0, lastWasCorrect: false, recentError: 0, comments: ''
        } as unknown as Question;

        finalQuestions.push(newQ);
    });

    // 3. Process Flashcards/Pairs
    flashcards.forEach(f => {
        const isPair = f.type === 'PAIR';
        const tags = [f.litRef, isPair ? 'pair-match' : 'literalness'].filter(Boolean);

        const newFc: Flashcard = {
            id: idGen.makeDeterministicId(f.litRef, isPair ? 'PAIR' : 'FLASHCARD', f.FC_REF || f.PAIR_REF),
            front: f.FRONT,
            back: f.BACK,
            discipline: normalizeDiscipline(f.discipline),
            topic: f.topic,
            tags: tags,
            type: 'basic',
            importBatchId: batchId,
            createdAt: today, updatedAt: today, nextReviewDate: today,
            masteryScore: 0, stability: settings.srsV2.S_default_days,
            totalAttempts: 0, attemptHistory: [], masteryHistory: [],
            hotTopic: false, isCritical: false, isFundamental: false,
            lastWasCorrect: false, recentError: 0, correctStreak: 0, srsStage: 0,
            lastAttemptDate: '', pairMatchPlayed: false, timeSec: 0, selfEvalLevel: 0, comments: f.COMMENTS || ''
        } as unknown as Flashcard;

        finalFlashcards.push(newFc);
    });

    return {
        isValid: issues.filter(i => i.severity === 'ERROR').length === 0,
        issues,
        stats: {
            articles: finalCards.length,
            questions: finalQuestions.length,
            flashcards: finalFlashcards.filter(f => !f.tags.includes('pair-match')).length,
            pairs: finalFlashcards.filter(f => f.tags.includes('pair-match')).length,
            gaps: finalGaps.length
        },
        parsedData: {
            nuclei: finalCards,
            questions: finalQuestions,
            flashcards: finalFlashcards,
            gaps: finalGaps
        }
    };
};

