import { buildReadingSteps } from './readingParser';
import { normalizeDiscipline } from './taxonomyService';
import { parseLitRefText } from './import/litRefParser';

// --- HELPERS ---

const createEmptyCount = (): ImportCountDetail => ({ received: 0, imported: 0, skipped: 0, normalized: 0 });

const normalizeOptions = (opts: any): { A: string, B: string, C: string, D: string, E: string } => {
    if (!opts) return { A: '', B: '', C: '', D: '', E: '' };
    return {
        A: opts.A || opts.a || opts.OPT_A || '',
        B: opts.B || opts.b || opts.OPT_B || '',
        C: opts.C || opts.c || opts.OPT_C || '',
        D: opts.D || opts.d || opts.OPT_D || '',
        E: opts.E || opts.e || opts.OPT_E || ''
    };
};

function asStringArray(v: unknown): string[] {
    if (!Array.isArray(v)) return [];
    return v.filter(x => typeof x === "string") as string[];
}

/**
 * Sanitiza o objeto de importação para garantir que ele esteja em conformidade com a interface LessonNode.
 * Remove arrays pesados (questions, lawCards) e garante defaults para campos obrigatórios.
 */
export function sanitizeLessonNode(imported: any, refsOverride?: { 
    questions?: string[], 
    flashcards?: string[] 
}): LessonNode {
    // 1. Identificadores
    const id = String(imported?.id || imported?.uid || `L_${Date.now()}_${Math.random().toString(36).substr(2,5)}`).trim();
    const uid = String(imported?.uid || id).trim();
    const title = String(imported?.title || "Nova Aula").trim();
    const code = String(imported?.code || "NO_CODE").trim();
    const subjectId = String(imported?.subjectId || "GERAL").trim();

    // 2. Metadados Leves
    const order = Number.isFinite(imported?.order) ? Number(imported.order) : 1;
    const themeTag = imported?.themeTag ? String(imported.themeTag) : undefined;

    // 3. Referências (Source of Truth)
    // Usa overrides (calculados no staging) ou tenta extrair apenas IDs do payload
    const questionRefs = refsOverride?.questions || 
      asStringArray(imported?.refs?.questions) ||
      (Array.isArray(imported?.questions) ? imported.questions.map((x: any) => String(x?.id || x?.Q_REF || "")).filter(Boolean) : []);

    const flashcardRefs = refsOverride?.flashcards ||
      asStringArray(imported?.refs?.flashcards) ||
      (Array.isArray(imported?.flashcards) ? imported.flashcards.map((x: any) => String(x?.id || x?.FC_REF || "")).filter(Boolean) : []);

    // 4. Conteúdo Textual (Arrays de Strings apenas)
    const keyPoints = asStringArray(imported?.keyPoints);

    // Summary normalizado
    let summary: string[] = [];
    if (typeof imported?.summary === 'string') summary = [imported.summary];
    else if (Array.isArray(imported?.summary)) summary = asStringArray(imported.summary);

    // Explanations normalizado (remove objetos complexos se houver)
    let explanations: string[] = [];
    if (Array.isArray(imported?.explanations)) {
        explanations = imported.explanations.map((e: any) => {
            if (typeof e === 'string') return e;
            if (e?.text) return e.text;
            return '';
        }).filter(Boolean);
    }

    // 5. Status & Progresso (Defaults Obrigatórios)
    const validStatuses: LessonStatus[] = ['locked', 'not_started', 'in_progress', 'review', 'mastered'];
    const status: LessonStatus = validStatuses.includes(imported?.status) ? imported.status : 'not_started';
    const domainLevel = Number.isFinite(imported?.domainLevel) ? Number(imported.domainLevel) : 0;

    // CONTRATO FINAL
    return {
        id,
        uid,
        subjectId: normalizeDiscipline(subjectId),
        title,
        code,
        order,
        status,
        domainLevel,
        keyPoints,
        summary,
        explanations,
        questionRefs,
        flashcardRefs,
        themeTag,
        successRate: typeof imported?.successRate === 'number' ? imported.successRate : undefined,
        lastSessionAt: imported?.lastSessionAt,
        nextReviewAt: imported?.nextReviewAt
    };
}

// --- PARSER LEI SECA ADAPTER ---
// Converte o resultado do parseLitRefText em LessonNode e StagingData

const processLeiSecaImport = (
    text: string, 
    settings: AppSettings,
    baseOrder: number = 1
): { report: ImportReport, staging: ImportStagingData, lessons: LessonNode[] } => {

    const batchId = `IMP_LS_${Date.now()}`;
    const timestamp = new Date().toISOString();

    // 1. Parse usando o serviço robusto existente
    const parsed = parseLitRefText(text, settings, batchId);

    const details: ImportDetail[] = [];

    // Fix: Access parsedData instead of direct properties on ParseDiagnosis
    const staging: ImportStagingData = {
        cards: parsed.parsedData.nuclei,
        questions: parsed.parsedData.questions,
        flashcards: parsed.parsedData.flashcards,
        gaps: parsed.parsedData.gaps || [] // Added gaps to staging from parsedData
    };

    const lessons: LessonNode[] = [];
    let errorCount = 0;

    // 2. Validação Estrita & Mapping para Lessons
    // Cada CARD (Núcleo) vira uma Lesson
    parsed.parsedData.nuclei.forEach((card, idx) => {
        const litRef = card.id;

        // Filter content related to this card using parsedData arrays
        const lessonQuestions = parsed.parsedData.questions.filter(q => srs.canonicalizeLitRef(q.lawRef) === srs.canonicalizeLitRef(litRef));
        // Pairs and Flashcards are in the same array in parseLitRefText output, distinguished by tags
        const lessonFlashcards = parsed.parsedData.flashcards.filter(f => srs.isLinked(f, litRef) && !f.tags?.includes('pair-match'));
        const lessonPairs = parsed.parsedData.flashcards.filter(f => srs.isLinked(f, litRef) && f.tags?.includes('pair-match'));
        const lessonGaps = parsed.parsedData.gaps.filter(g => srs.canonicalizeLitRef(g.litRef) === srs.canonicalizeLitRef(litRef));

        // STRICT VALIDATION RULES
        // A5) Lacunas >= 6
        if (lessonGaps.length < 6) {
            details.push({ entityType: 'gap', ref: litRef, action: 'ERROR', reasonCode: 'MIN_COUNT_FAIL', message: `Mínimo 6 lacunas exigido. Encontrado: ${lessonGaps.length}.` });
            errorCount++;
        }

        // A6) Questões == 20
        if (lessonQuestions.length !== 20) {
            details.push({ entityType: 'question', ref: litRef, action: 'ERROR', reasonCode: 'STRICT_COUNT_FAIL', message: `Exatamente 20 questões exigidas. Encontrado: ${lessonQuestions.length}.` });
            errorCount++;
        }

        // A7) Flashcards >= 6
        if (lessonFlashcards.length < 6) {
            details.push({ entityType: 'flashcard', ref: litRef, action: 'ERROR', reasonCode: 'MIN_COUNT_FAIL', message: `Mínimo 6 flashcards exigido. Encontrado: ${lessonFlashcards.length}.` });
            errorCount++;
        }

        // A8) Pares >= 6
        if (lessonPairs.length < 6) {
            details.push({ entityType: 'pair', ref: litRef, action: 'ERROR', reasonCode: 'MIN_COUNT_FAIL', message: `Mínimo 6 pares exigido. Encontrado: ${lessonPairs.length}.` });
            errorCount++;
        }

        // Mapping Gaps to Card Structure (Crucial Fix for Gaps)
        const mappedGaps = lessonGaps.map(g => ({
             id: g.id,
             text: g.payload.lacuna_text || g.payload.text,
             correct: g.payload.correct_letter || g.payload.correct || 'A',
             options: g.payload.options || { A: 'Erro' },
             questionRef: `GAP-${g.payload.idx || '?'}`
        }));

        // Update the card in staging with the mapped gaps
        const cardIndex = staging.cards.findIndex(c => c.id === card.id);
        if (cardIndex !== -1) {
             staging.cards[cardIndex].extraGaps = mappedGaps;
        }

        // Mapping to LessonNode
        // Title = Tópico ou Artigo
        const title = card.topic !== 'Geral' ? `${card.article} - ${card.topic}` : card.article;

        // Explanation / Summary derived from Card fields
        const summary = [card.partsSummary || 'Resumo não disponível.'];
        const explanations = [
            `Conceito: ${card.phase1Full}`,
            card.storytelling ? `Storytelling: ${card.storytelling}` : '',
            card.feynmanExplanation ? `Feynman: ${card.feynmanExplanation}` : '',
            card.riscoFcc ? `Risco: ${card.riscoFcc}` : ''
        ].filter(Boolean);

        // Collect ALL IDs for refs
        const questionIds = lessonQuestions.map(q => q.id);
        const flashcardIds = [...lessonFlashcards, ...lessonPairs].map(f => f.id);

        const lesson: LessonNode = {
            id: litRef, // Use LitRef as ID for stable mapping
            uid: litRef,
            subjectId: normalizeDiscipline(card.lawId),
            title: title,
            code: litRef,
            order: baseOrder + idx,
            status: 'not_started',
            domainLevel: 0,
            keyPoints: card.keywordsProva ? card.keywordsProva.split(';').map(s=>s.trim()) : [],
            summary: summary,
            explanations: explanations,
            questionRefs: questionIds,
            flashcardRefs: flashcardIds, // Includes Pairs!
            themeTag: 'LEI SECA'
        };

        lessons.push(lesson);
    });

    const counts = {
        lawCards: { received: parsed.stats.articles, imported: parsed.stats.articles, skipped: 0, normalized: 0 },
        questions: { received: parsed.stats.questions, imported: parsed.stats.questions, skipped: 0, normalized: 0 },
        flashcards: { received: parsed.stats.flashcards, imported: parsed.stats.flashcards, skipped: 0, normalized: 0 },
        pairs: { received: parsed.stats.pairs, imported: parsed.stats.pairs, skipped: 0, normalized: 0 },
        gaps: { received: parsed.stats.gaps, imported: parsed.stats.gaps, skipped: 0, normalized: 0 }
    };

    const status = errorCount > 0 ? 'FAILED' : 'SUCCESS';

    // Fix TS2322: Map ParseIssue objects to strings using template literal
    const formattedDetails = [
        ...details,
        ...parsed.issues.map(e => ({
            entityType: 'meta' as ImportEntityType,
            ref: 'PARSER',
            action: 'NORMALIZED' as any,
            reasonCode: 'WARNING',
            message: `[Line ${e.line}] ${e.message} (${e.suggestion})`
        }))
    ];

    const report: ImportReport = {
        importId: batchId,
        timestamp,
        summary: {
            status,
            totalEntities: counts.lawCards.received + counts.questions.received + counts.flashcards.received + counts.pairs.received + counts.gaps.received,
            importedEntities: counts.lawCards.imported + counts.questions.imported + counts.flashcards.imported + counts.pairs.imported + counts.gaps.imported,
            skippedEntities: counts.lawCards.skipped + counts.questions.skipped + counts.flashcards.skipped + counts.pairs.skipped + counts.gaps.skipped,
            normalizedEntities: warningCount,
            errorsCount: errorCount,
            warningsCount: warningCount
        },
        counts,
        details: formattedDetails
    };

    return {
        report,
        staging: status === 'FAILED' ? { cards: [], questions: [], flashcards: [], gaps: [] } : staging,
        lessons: status === 'FAILED' ? [] : lessons
    };
};

// --- CORE GENERATOR ---

export const generateImportReport = (
    rawInput: string,
    existingQuestions: Question[],
    existingCards: LiteralnessCard[],
    existingFlashcards: Flashcard[],
    settings: AppSettings,
    context?: { subjectId: string, title: string, uid?: string } // Fallback context if not provided in JSON
): { report: ImportReport, staging: ImportStagingData | null, lessons?: LessonNode[] } => {

    const trimmed = rawInput.trim();
    const isJson = trimmed.startsWith('[') || trimmed.startsWith('{');

    // ROUTE 1: LEI SECA FORMAT (TEXT)
    if (!isJson && trimmed.includes('LIT_REF:')) {
        // Assume basic order starts at 1, or try to detect max order from existing trails if needed (omitted for simplicity)
        return processLeiSecaImport(rawInput, settings, 1);
    }

    // ROUTE 2: JSON LEGACY FORMAT
    const importId = `IMP_${Date.now()}`;
    const timestamp = new Date().toISOString();
    const details: ImportDetail[] = [];

    const counts = {
        lawCards: createEmptyCount(),
        gaps: createEmptyCount(),
        questions: createEmptyCount(),
        flashcards: createEmptyCount(),
        pairs: createEmptyCount(),
    };

    const staging: ImportStagingData = { cards: [], questions: [], flashcards: [], gaps: [] };

    // --- PARSE JSON ---
    let modules: any[] = [];
    try {
        const parsed = JSON.parse(trimmed);
        modules = Array.isArray(parsed) ? parsed : [parsed];
    } catch (e: any) {
        return {
            report: {
                importId, timestamp,
                summary: { status: 'FAILED', errorsCount: 1, warningsCount: 0, totalEntities: 0, importedEntities: 0, skippedEntities: 0, normalizedEntities: 0 },
                counts,
                details: [{ entityType: 'meta', ref: 'JSON', action: 'ERROR', reasonCode: 'INVALID_JSON', message: e.message, path: '$' }]
            },
            staging: null
        };
    }

    const today = srs.todayISO();

    // Sets for uniqueness check within batch
    const batchQRefs = new Set<string>();
    const batchCardRefs = new Set<string>();

    modules.forEach((mod, modIdx) => {
        // --- 1. MODULE VALIDATION ---
        const modId = mod.uid || mod.id; // Allow id as fallback but convert to internal uid concept if needed
        const subjectId = normalizeDiscipline(mod.subjectId || context?.subjectId);
        const title = mod.title || context?.title || `Módulo ${modIdx + 1}`;

        if (!subjectId) {
             details.push({ entityType: 'module', ref: title, action: 'ERROR', reasonCode: 'MISSING_SUBJECT', message: 'SubjectID obrigatório.', path: `$[${modIdx}].subjectId`, moduleId: modId });
        }

        // --- 2. LAW CARDS ---
        const lawCards = Array.isArray(mod.lawCards) ? mod.lawCards : [];
        counts.lawCards.received += lawCards.length;

        lawCards.forEach((lc: any, i: number) => {
            // Updated to prefer LC_REF
            const litRef = srs.canonicalizeLitRef(lc.LC_REF || lc.LIT_REF || lc.litRef || lc.id);
            const path = `$[${modIdx}].lawCards[${i}]`;

            if (!litRef) {
                details.push({ entityType: 'lawCard', ref: 'UNKNOWN', action: 'SKIPPED', reasonCode: 'MISSING_REF', message: 'LC_REF/LIT_REF ausente.', path, moduleId: modId });
                counts.lawCards.skipped++;
                return;
            }

            if (batchCardRefs.has(litRef)) {
                 details.push({ entityType: 'lawCard', ref: litRef, action: 'SKIPPED', reasonCode: 'DUPLICATE_IN_BATCH', message: 'Card duplicado no lote.', path, moduleId: modId });
                 counts.lawCards.skipped++;
                 return;
            }
            batchCardRefs.add(litRef);

            const newCard: LiteralnessCard = {
                id: litRef,
                lawId: subjectId, // Grouping key
                article: lc.ARTICLE || lc.LC_REF || lc.title || 'Artigo',
                topic: lc.TOPIC_TITLE || lc.TOPIC || title,
                phase1Full: lc.PHASE1_FULL || lc.text || '',
                partsSummary: lc.RESUMO_POR_PARTES || lc.partsSummary || '',
                keywordsProva: lc.KEYWORDS_PROVA || lc.keywords || '',
                riscoFcc: lc.RISCO_FCC || lc.risco || '',
                gancho: lc.GANCHO_MNEMONICO || lc.gancho || '',
                storytelling: lc.STORYTELLING || '',
                feynmanExplanation: lc.FEYNMAN || '',
                createdAt: today, nextReviewDate: today, lastReviewedAt: today,
                masteryScore: 0, totalAttempts: 0, stability: 1, batteryProgress: 0, progressionLevel: 0,
                importBatchId: importId, extraGaps: [], contentType: 'LAW_DRY'
            };

            newCard.studyFlow = buildReadingSteps(newCard); // Generate steps
            (newCard as any)._moduleIndex = modIdx; // TRACKER
            staging.cards.push(newCard);
            counts.lawCards.imported++;
        });

        // --- 3. QUESTIONS ---
        const questions = Array.isArray(mod.questions) ? mod.questions : [];
        counts.questions.received += questions.length;

        questions.forEach((q: any, i: number) => {
            const qRef = q.Q_REF || q.questionRef || q.id;
            const path = `$[${modIdx}].questions[${i}]`;

            if (!qRef) {
                details.push({ entityType: 'question', ref: 'UNKNOWN', action: 'SKIPPED', reasonCode: 'MISSING_REF', message: 'Q_REF obrigatório.', path, moduleId: modId });
                counts.questions.skipped++;
                return;
            }

            if (batchQRefs.has(qRef)) {
                 details.push({ entityType: 'question', ref: qRef, action: 'SKIPPED', reasonCode: 'DUPLICATE_IN_BATCH', message: 'Questão duplicada no lote.', path, moduleId: modId });
                 counts.questions.skipped++;
                 return;
            }

            const lawRef = srs.canonicalizeLitRef(q.LAW_REF || q.lawRef || q.litRef);

            const correct = (q.CORRECT || q.correctAnswer || 'A').toUpperCase().trim().charAt(0);
            const options = normalizeOptions(q.options || q); // Normalize using q directly if OPT_A keys are at root

            if (!options.A || !options.B) {
                 if (q.TYPE?.includes('C/E') || correct === 'C' || correct === 'E') {
                     options.A = 'Certo'; options.B = 'Errado';
                 } else {
                     details.push({ entityType: 'question', ref: qRef, action: 'SKIPPED', reasonCode: 'INVALID_OPTIONS', message: 'Opções insuficientes.', path, moduleId: modId });
                     counts.questions.skipped++;
                     return;
                 }
            }

            const stableId = idGen.makeDeterministicId(lawRef || 'GERAL', 'QUESTION', qRef);
            batchQRefs.add(qRef);

            const newQ: Question = {
                id: stableId,
                questionRef: qRef,
                questionText: q.Q_TEXT || q.STEM || q.questionText || '...',
                options,
                correctAnswer: correct,
                subject: subjectId,
                topic: q.TOPIC || title,
                lawRef: lawRef || '', // Canonical link

                guiaTrapscan: q.GUIA_TRAPSCAN || q.guiaTrapscan || '',
                keyDistinction: q.KEY_DISTINCTION || q.keyDistinction,
                anchorText: q.ANCHOR_TEXT || q.anchorText,
                wrongDiagnosis: q.WRONG_DIAGNOSIS || q.wrongDiagnosis,
                explanationTech: q.EXPLANATION || q.EXPLANATION_TECH || q.explanationTech,
                explanationStory: q.EXPLANATION_STORY || q.explanationStory,

                // --- NOVOS CAMPOS MAPEADOS ---
                feynmanQuestions: q.PERGUNTAS_FEYNMAN || q.feynmanQuestions || q.feynman,
                distractorProfile: q.DISTRACTOR_PROFILE || q.distractorProfile,
                wrongDiagnosisMap: q.WRONG_DIAGNOSIS_MAP || q.wrongDiagnosisMap,
                // -----------------------------

                // Extra fields from TRAPSCAN object if present at root
                ...((q.TRAPSCAN) ? {
                     guiaTrapscan: JSON.stringify(q.TRAPSCAN),
                     keyDistinction: q.TRAPSCAN.P1_TERMO_ALVO || q.TRAPSCAN.KEY_DISTINCTION,
                     // Map other trapscan fields if needed, or store whole object
                } : {}),

                createdAt: today, nextReviewDate: today, totalAttempts: 0, masteryScore: 0,
                stability: settings.srsV2.S_default_days, attemptHistory: [],
                questionType: q.TYPE || 'Literalidade', difficultyLevel: 'normal',
                importBatchId: importId, sequenceNumber: 0, comments: '',
                lastAttemptDate: '', errorCount: 0, timeSec: 0, selfEvalLevel: 0,
                willFallExam: false, srsStage: 0, correctStreak: 0, lastWasCorrect: false, recentError: 0
            } as any;

            (newQ as any)._moduleIndex = modIdx; // TRACKER
            staging.questions.push(newQ);
            counts.questions.imported++;
        });

        // --- 4. GAPS ---
        const gaps = Array.isArray(mod.gaps) ? mod.gaps : [];
        counts.gaps.received += gaps.length;

        gaps.forEach((g: any, i: number) => {
             const gapRef = g.GAP_REF || g.id || `GAP_${i}`;
             // Try to infer litRef from parent or generate if missing
             const litRef = srs.canonicalizeLitRef(g.LIT_REF || g.litRef || `GAP_LIT_${modIdx}`);

             // Gaps don't strictly require LIT_REF for import if they are part of a lesson structure
             // But for SRS linkage it is better.

             const gapId = idGen.makeDeterministicId(litRef, 'LACUNA', gapRef);

             staging.gaps.push({
                 id: gapId,
                 litRef,
                 type: 'LACUNA',
                 payload: {
                     lacuna_text: g.TEXT_WITH_BLANKS || g.GAP_TEXT || g.text || g.PHASE2_LACUNA,
                     correct_text: g.ANSWER || g.correct_text, // Add correct text field support
                     correct_letter: g.PHASE2_CORRECT || g.correct || 'A',
                     options: normalizeOptions(g.options || { A: g.PHASE2_OPT_A, B: g.PHASE2_OPT_B, C: g.PHASE2_OPT_C, D: g.PHASE2_OPT_D, E: g.PHASE2_OPT_E })
                 }
             });
             counts.gaps.imported++;
        });

        // --- 5. FLASHCARDS & PAIRS ---
        const flashcards = Array.isArray(mod.flashcards) ? mod.flashcards : [];
        const pairs = Array.isArray(mod.pairs) ? mod.pairs : [];

        const processFc = (f: any, i: number, isPair: boolean) => {
            const listName = isPair ? 'pairs' : 'flashcards';
            const countObj = isPair ? counts.pairs : counts.flashcards;
            countObj.received++;

            const ref = f.FC_REF || f.PAIR_REF || f.id || `${listName}_${i}`;
            const path = `$[${modIdx}].${listName}[${i}]`;

            if (!f.front && !f.FRONT) {
                 details.push({ entityType: isPair ? 'pair' : 'flashcard', ref, action: 'SKIPPED', reasonCode: 'MISSING_CONTENT', message: 'Sem frente/verso.', path, moduleId: modId });
                 countObj.skipped++;
                 return;
            }

            const litRef = srs.canonicalizeLitRef(f.LIT_REF || f.litRef);
            const stableId = idGen.makeDeterministicId(litRef || subjectId, isPair ? 'PAIR' : 'FLASHCARD', ref);

            const tags = [...(f.tags || []), f.TAGS, litRef].flat().filter(Boolean);
            if (isPair) tags.push('pair-match');

            const newFc: Flashcard = {
                id: stableId,
                front: f.FRONT || f.front,
                back: f.BACK || f.back,
                discipline: subjectId,
                topic: f.TOPIC_TITLE || f.TOPIC || title,
                tags,
                type: 'basic',
                importBatchId: importId,
                createdAt: today, updatedAt: today, nextReviewDate: today,
                masteryScore: 0, stability: settings.srsV2.S_default_days,
                totalAttempts: 0, attemptHistory: [], masteryHistory: [],
                hotTopic: false, isCritical: false, isFundamental: false,
                lastWasCorrect: false, recentError: 0, correctStreak: 0, srsStage: 0,
                lastAttemptDate: '', pairMatchPlayed: false, timeSec: 0, selfEvalLevel: 0, comments: f.COMMENTS || ''
            };

            (newFc as any)._moduleIndex = modIdx; // TRACKER
            staging.flashcards.push(newFc);
            countObj.imported++;
        };

        flashcards.forEach((f: any, i: number) => processFc(f, i, false));
        pairs.forEach((p: any, i: number) => processFc(p, i, true));
    });

    // --- FINAL REPORT ---
    const errorCount = details.filter(d => d.action === 'ERROR').length;
    const warningCount = details.filter(d => d.action === 'NORMALIZED').length;

    let status: "SUCCESS" | "PARTIAL_SUCCESS" | "FAILED" = "SUCCESS";
    if (errorCount > 0) status = "FAILED";
    else if (details.some(d => d.action === 'SKIPPED')) status = "PARTIAL_SUCCESS";

    const report: ImportReport = {
        importId,
        timestamp,
        summary: {
            status,
            totalEntities: counts.lawCards.received + counts.questions.received + counts.flashcards.received + counts.pairs.received + counts.gaps.received,
            importedEntities: counts.lawCards.imported + counts.questions.imported + counts.flashcards.imported + counts.pairs.imported + counts.gaps.imported,
            skippedEntities: counts.lawCards.skipped + counts.questions.skipped + counts.flashcards.skipped + counts.pairs.skipped + counts.gaps.skipped,
            normalizedEntities: warningCount,
            errorsCount: errorCount,
            warningsCount: warningCount
        },
        counts,
        details
    };

    return { report, staging: status === 'FAILED' ? null : staging };
};

import React, { useState, useMemo, useRef } from 'react';
import { useLiteralnessDispatch, useLiteralnessState } from '../../contexts/LiteralnessContext';
import { useQuestionDispatch } from '../../contexts/QuestionContext';
import { useFlashcardDispatch } from '../../contexts/FlashcardContext';
import { useSettings } from '../../contexts/SettingsContext';
import { LiteralnessCard, Question, Flashcard, LawContentType } from '../../types';
import * as srs from '../../services/srsService';
import { parseLitRefText, ParseDiagnosis, ParseIssue } from '../../services/import/litRefParser';
import { nucleusRepo } from '../../services/repositoryService';
import { 
    CheckCircleIcon, XMarkIcon, CloudIcon, ChevronLeftIcon, 
    ExclamationTriangleIcon, BoltIcon, TrashIcon, ArrowPathIcon
} from '../icons';

interface ImportLiteralnessProps {
    type?: LawContentType;
    onBack?: () => void;
    forcedLawId?: string | null;
}

const ImportLiteralness: React.FC<ImportLiteralnessProps> = ({ type = 'LAW_DRY', onBack }) => {
    const { addBatchCards } = useLiteralnessDispatch();
    const { addBatchQuestions } = useQuestionDispatch();
    const { addBatchFlashcards } = useFlashcardDispatch();
    const { settings } = useSettings();
    const allCards = useLiteralnessState();

    const [text, setText] = useState('');
    const [diagnosis, setDiagnosis] = useState<ParseDiagnosis | null>(null);
    const [isProcessing, setIsProcessing] = useState(false);
    const textareaRef = useRef<HTMLTextAreaElement>(null);

    // --- ACTIONS ---

    const handleAnalyze = () => {
        if (!text.trim()) return;
        setIsProcessing(true);
        setTimeout(() => {
            const batchId = `BATCH_${Date.now()}`;
            const result = parseLitRefText(text, settings, batchId);
            setDiagnosis(result);
            setIsProcessing(false);
        }, 100); // Async simulation for UI response
    };

    const handleImport = async (mode: 'OVERWRITE' | 'MERGE' | 'SKIP') => {
        if (!diagnosis || !diagnosis.isValid) return;
        setIsProcessing(true);

        try {
            const batch = {
                cards: diagnosis.parsedData.nuclei,
                questions: diagnosis.parsedData.questions,
                flashcards: diagnosis.parsedData.flashcards
            };

            // Process based on mode (Logic delegated to Repository to keep UI clean)
            // Note: Repository handles "Overwrite" by replacing children. 
            // "Skip" logic is: filter out existing cards from batch before saving.

            if (mode === 'SKIP') {
                const existingIds = new Set(allCards.map(c => c.id));
                batch.cards = batch.cards.filter(c => !existingIds.has(c.id));
                // We also filter children to only include those for new cards
                // (Assuming Skip means "Don't touch existing articles at all")
                const newCardIds = new Set(batch.cards.map(c => c.id));
                batch.questions = batch.questions.filter(q => newCardIds.has(srs.canonicalizeLitRef(q.lawRef)));
                batch.flashcards = batch.flashcards.filter(f => newCardIds.has(srs.resolveLitRef(f)));
            }

            // Use Repository Service for Robust Save (Transactional-ish)
            await nucleusRepo.saveImportBatch(batch);

            // Refresh Contexts (The providers effectively reload from DB or we push directly)
            // For now, we push to dispatchers to update UI state immediately
            addBatchCards(batch.cards);
            addBatchQuestions(batch.questions, mode === 'OVERWRITE' ? 'OVERWRITE' : 'MERGE'); 
            addBatchFlashcards(batch.flashcards);

            alert(`Importação concluída (${mode})!\n${batch.cards.length} Artigos processados.`);
            setDiagnosis(null);
            setText('');

        } catch (e: any) {
            alert(`Erro ao salvar: ${e.message}`);
        } finally {
            setIsProcessing(false);
        }
    };

    // --- UI HELPERS ---

    const highlightError = (line: number) => {
        if (textareaRef.current) {
            const lines = text.split('\n');
            let start = 0;
            for (let i = 0; i < line - 1; i++) {
                start += lines[i].length + 1; // +1 for newline
            }
            const end = start + lines[line - 1].length;

            textareaRef.current.focus();
            textareaRef.current.setSelectionRange(start, end);
            textareaRef.current.scrollTop = start / 3; // Approx scroll
        }
    };

    // --- RENDER ---

    return (
        <div className="max-w-6xl mx-auto space-y-6 pb-24 animate-fade-in px-4 h-full flex flex-col">

            {/* Header */}
            <div className="flex justify-between items-center bg-slate-900/80 p-4 rounded-2xl border border-white/10 backdrop-blur shrink-0">
                <div className="flex items-center gap-3">
                    <CloudIcon className="text-sky-400 w-8 h-8" />
                    <div>
                        <h3 className="text-xl font-black text-white italic tracking-tighter">Importador Lei Seca</h3>
                        <p className="text-xs text-slate-500 font-bold uppercase tracking-widest">Parser v2.0 • Blocos • Validação</p>
                    </div>
                </div>
                {onBack && <button onClick={onBack} className="p-2 bg-white/5 rounded-full hover:bg-white/10 text-slate-400 hover:text-white"><XMarkIcon className="w-5 h-5"/></button>}
            </div>

            <div className="flex-1 grid grid-cols-1 lg:grid-cols-2 gap-6 min-h-0">

                {/* LEFT: Editor */}
                <div className="flex flex-col gap-4 h-full">
                    <div className="flex-1 bg-slate-900 border border-white/10 rounded-2xl p-1 relative">
                        <textarea 
                            ref={textareaRef}
                            value={text} 
                            onChange={(e) => { setText(e.target.value); if(diagnosis) setDiagnosis(null); }} 
                            className="w-full h-full bg-transparent p-4 text-xs font-mono text-sky-100 outline-none resize-none leading-relaxed custom-scrollbar whitespace-pre" 
                            placeholder="Cole aqui seu conteúdo (LIT_REF: ...)"
                            spellCheck={false}
                        />
                        {/* Line Numbers Overlay could go here if needed */}
                    </div>
                    <div className="flex justify-between items-center shrink-0">
                         <button onClick={() => setText('')} className="text-slate-500 hover:text-rose-500 p-2"><TrashIcon className="w-5 h-5"/></button>
                         <button 
                            onClick={handleAnalyze} 
                            disabled={!text.trim() || isProcessing}
                            className="bg-sky-600 hover:bg-sky-500 text-white font-black px-8 py-3 rounded-xl shadow-lg transition-all active:scale-95 flex items-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
                         >
                             {isProcessing ? <ArrowPathIcon className="w-4 h-4 animate-spin"/> : <BoltIcon className="w-4 h-4"/>}
                             ANALISAR TEXTO
                         </button>
                    </div>
                </div>

                {/* RIGHT: Diagnostics & Actions */}
                <div className="flex flex-col gap-4 h-full overflow-hidden">
                    {diagnosis ? (
                        <div className="flex flex-col h-full bg-slate-900/50 border border-white/10 rounded-2xl overflow-hidden">
                            {/* Stats Header */}
                            <div className="p-4 border-b border-white/5 bg-slate-900/80 grid grid-cols-3 gap-2 text-center shrink-0">
                                <div className="p-2 bg-white/5 rounded-lg"><span className="block text-xl font-black text-white">{diagnosis.stats.articles}</span><span className="text-[8px] uppercase text-slate-500 font-bold">Artigos</span></div>
                                <div className="p-2 bg-white/5 rounded-lg"><span className="block text-xl font-black text-sky-400">{diagnosis.stats.questions}</span><span className="text-[8px] uppercase text-slate-500 font-bold">Questões</span></div>
                                <div className="p-2 bg-white/5 rounded-lg"><span className="block text-xl font-black text-emerald-400">{diagnosis.stats.flashcards + diagnosis.stats.pairs}</span><span className="text-[8px] uppercase text-slate-500 font-bold">Cards</span></div>
                            </div>

                            {/* Issues List */}
                            <div className="flex-1 overflow-y-auto custom-scrollbar p-4 space-y-2">
                                {diagnosis.issues.length === 0 ? (
                                    <div className="text-center py-10 opacity-50">
                                        <CheckCircleIcon className="w-12 h-12 text-emerald-500 mx-auto mb-2"/>
                                        <p className="text-sm font-bold text-emerald-400">Nenhum erro encontrado.</p>
                                    </div>
                                ) : (
                                    diagnosis.issues.map((issue, idx) => (
                                        <div 
                                            key={idx} 
                                            onClick={() => highlightError(issue.line)}
                                            className={`p-3 rounded-xl border cursor-pointer hover:bg-white/5 transition-all ${issue.severity === 'ERROR' ? 'bg-rose-500/10 border-rose-500/30' : 'bg-amber-500/10 border-amber-500/30'}`}
                                        >
                                            <div className="flex justify-between items-center mb-1">
                                                <span className={`text-[9px] font-black uppercase px-1.5 py-0.5 rounded ${issue.severity === 'ERROR' ? 'bg-rose-500 text-white' : 'bg-amber-500 text-black'}`}>
                                                    {issue.severity}
                                                </span>
                                                <span className="text-[10px] font-mono text-slate-500">Linha {issue.line}</span>
                                            </div>
                                            <p className="text-xs text-white font-medium mb-1"><span className="opacity-50">[{issue.block}]</span> {issue.message}</p>
                                            <p className="text-[10px] text-sky-400 font-bold">💡 {issue.suggestion}</p>
                                        </div>
                                    ))
                                )}
                            </div>

                            {/* Action Buttons */}
                            <div className="p-4 border-t border-white/5 bg-slate-900/80 shrink-0">
                                {diagnosis.isValid ? (
                                    <div className="grid grid-cols-3 gap-2">
                                        <button onClick={() => handleImport('SKIP')} className="py-3 rounded-xl border border-white/10 hover:bg-white/5 text-slate-400 font-bold text-[10px] uppercase">Ignorar Existentes</button>
                                        <button onClick={() => handleImport('MERGE')} className="py-3 rounded-xl bg-sky-600 hover:bg-sky-500 text-white font-bold text-[10px] uppercase shadow-lg">Mesclar (Update)</button>
                                        <button onClick={() => handleImport('OVERWRITE')} className="py-3 rounded-xl bg-amber-600 hover:bg-amber-500 text-white font-black text-[10px] uppercase shadow-lg">Sobrescrever</button>
                                    </div>
                                ) : (
                                    <div className="bg-rose-500/10 border border-rose-500/20 p-3 rounded-xl text-center">
                                        <p className="text-xs font-bold text-rose-400">Corrija os erros acima para importar.</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    ) : (
                        <div className="h-full flex flex-col items-center justify-center text-center opacity-30 border-2 border-dashed border-slate-700 rounded-2xl">
                            <BoltIcon className="w-16 h-16 mb-4 text-slate-500"/>
                            <p className="text-sm font-bold text-slate-400 uppercase tracking-widest">Aguardando Análise</p>
                        </div>
                    )}
                </div>

            </div>
        </div>
    );
};

export default ImportLiteralness;

import * as storage from './storage';
import { LiteralnessCard, Question, Flashcard, SrsItem } from '../types';
import * as srs from './srsService';

/**
 * Repository Service
 * Centralizes all cross-store data access to ensure LIT_REF integrity.
 */

export const nucleusRepo = {
    /**
     * Rehydrates an article completely, fetching linked content directly from DB 
     * to avoid "missing items" UI bugs.
     */
    async getFullArticleData(litRef: string) {
        const canon = srs.canonicalizeLitRef(litRef);

        // 1. Get Core Card
        const cards = await storage.loadData<LiteralnessCard[]>('revApp_literalness_v1') || [];
        const card = cards.find(c => srs.canonicalizeLitRef(c.id) === canon);

        if (!card) return null;

        // 2. Direct Index Search in DB (Source of Truth)
        // Fix: storage.STORES.QUESTIONS/FLASHCARDS do not exist. Using STORES.CONTENT and filtering by type.
        const allItems = await storage.dbGetByIndex<any>(storage.STORES.CONTENT, 'litRef', canon);
        const questions = allItems.filter(i => i.type === 'QUESTION').map(i => i.payload as Question);
        const flashcards = allItems.filter(i => i.type === 'FLASHCARD' || i.type === 'PAIR').map(i => i.payload as Flashcard);

        return {
            card,
            questions: questions.filter(q => !q.isGapType),
            gaps: srs.getGapsForCard(card, questions),
            flashcards: flashcards.filter(f => !f.tags?.includes('pair-match')),
            pairs: flashcards.filter(f => f.tags?.includes('pair-match'))
        };
    },

    /**
     * Persists imported batch ensuring immutability rules.
     * IMPLEMENTS UPSERT AND CHILD REPLACEMENT STRATEGY.
     */
    async saveImportBatch(batch: { cards: LiteralnessCard[], questions: Question[], flashcards: Flashcard[] }) {
        // 1. Upsert Nucleus Cards
        // Since we are using put, it overwrites if ID exists (Upsert).
        await storage.dbPut(storage.STORES.NUCLEUS, batch.cards);

        // 2. Handle Content Synchronization (Replace Children)
        // For each card in the batch, we must ensure the DB state matches the batch state for its children.
        // Any child in DB that is NOT in the batch must be deleted (Pruning).

        const contentStoreName = storage.STORES.CONTENT;
        const db = await storage.openDB();

        for (const card of batch.cards) {
            const litRef = card.id;

            // A. Get existing children from DB for this Card
            // This is crucial: we fetch what is currently stored for this LitRef
            const existingItems = await storage.dbGetByIndex<any>(contentStoreName, 'litRef', litRef);

            // B. Get new children from Batch for this Card
            // We use canonical LitRef to match
            const newQuestions = batch.questions.filter(q => srs.canonicalizeLitRef(q.lawRef) === litRef);
            const newFlashcards = batch.flashcards.filter(fc => srs.isLinked(fc, litRef));

            const newIds = new Set<string>();
            const contentPayloads: any[] = [];

            // Prepare new payloads and collect IDs
            newQuestions.forEach(q => {
                 newIds.add(q.id);
                 contentPayloads.push({
                    id: q.id,
                    litRef: litRef,
                    type: 'QUESTION',
                    payload: q
                 });
            });

            newFlashcards.forEach(fc => {
                newIds.add(fc.id);
                contentPayloads.push({
                    id: fc.id,
                    litRef: litRef,
                    type: fc.tags?.includes('pair-match') ? 'PAIR' : 'FLASHCARD',
                    payload: fc
                });
            });

            // C. Identify Orphans (Exist in DB but not in New Batch)
            // If the batch updates the card, any question NOT in the batch should be considered "Deleted" or "Archived"
            const orphans = existingItems.filter(item => !newIds.has(item.id));

            // D. Delete Orphans
            if (orphans.length > 0) {
                console.log(`[Repository] Pruning ${orphans.length} orphans for ${litRef}`);
                const tx = db.transaction(contentStoreName, 'readwrite');
                const store = tx.objectStore(contentStoreName);
                orphans.forEach(o => store.delete(o.id));
                await new Promise(resolve => tx.oncomplete = resolve);
            }

            // E. Upsert New Content
            if (contentPayloads.length > 0) {
                 await storage.dbPut(contentStoreName, contentPayloads);
            }
        }

        // Sync with legacy stores for context compatibility (keeping this for now as per original code)
        // (In a full migration, we'd remove the legacy loadData calls)
        const existingCards = await storage.loadData<LiteralnessCard[]>('revApp_literalness_v1') || [];
        const existingQs = await storage.loadData<Question[]>('revApp_questions_v5_react') || [];
        const existingFs = await storage.loadData<Flashcard[]>('revApp_flashcards_v1') || [];

        // For Legacy Stores, we also need to apply the upsert/replace logic partially
        // Filter out old versions of the cards we are importing
        const batchCardIds = new Set(batch.cards.map(c => c.id));
        const batchQuestionIds = new Set(batch.questions.map(q => q.id));
        const batchFlashcardIds = new Set(batch.flashcards.map(f => f.id));

        const updatedCards = [...existingCards.filter(ec => !batchCardIds.has(ec.id)), ...batch.cards];
        const updatedQs = [...existingQs.filter(eq => !batchQuestionIds.has(eq.id)), ...batch.questions];
        const updatedFs = [...existingFs.filter(ef => !batchFlashcardIds.has(ef.id)), ...batch.flashcards];

        await storage.saveData('revApp_literalness_v1', updatedCards);
        await storage.saveData('revApp_questions_v5_react', updatedQs);
        await storage.saveData('revApp_flashcards_v1', updatedFs);
    },

    /**
     * FULL BATCH DELETION
     * Deletes the nucleus and all related content (Questions, Flashcards, Progress)
     * Returns the IDs of deleted items to allow UI state synchronization.
     */
    async deleteNucleus(litRef: string): Promise<{ deletedQuestions: string[], deletedFlashcards: string[] }> {
        const canon = srs.canonicalizeLitRef(litRef);
        console.log(`[Repository] Deleting Nucleus: ${canon}`);

        // 1. Fetch children IDs first (so we know what to remove from Context state)
        const allItems = await storage.dbGetByIndex<any>(storage.STORES.CONTENT, 'litRef', canon);
        const deletedQuestions = allItems.filter(i => i.type === 'QUESTION' || i.type === 'LACUNA').map(i => i.id);
        const deletedFlashcards = allItems.filter(i => i.type === 'FLASHCARD' || i.type === 'PAIR').map(i => i.id);

        // 2. Perform Atomic Delete in DB
        await storage.deleteAtomicBatch(canon);

        // 3. Clean Legacy LocalStorage to match DB
        // (This step is technically redundant if apps relied purely on DB, but necessary for current hybrid architecture)
        const legacyCards = await storage.loadData<LiteralnessCard[]>('revApp_literalness_v1') || [];
        const legacyQs = await storage.loadData<Question[]>('revApp_questions_v5_react') || [];
        const legacyFs = await storage.loadData<Flashcard[]>('revApp_flashcards_v1') || [];

        const nextCards = legacyCards.filter(c => srs.canonicalizeLitRef(c.id) !== canon);
        // Note: Legacy Questions might not have litRef property set correctly if older, 
        // so we filter by the IDs we found in the content store as well as the ref match.
        const nextQs = legacyQs.filter(q => !deletedQuestions.includes(q.id) && srs.canonicalizeLitRef(q.lawRef) !== canon);
        const nextFs = legacyFs.filter(f => !deletedFlashcards.includes(f.id) && srs.canonicalizeLitRef(f.litRef) !== canon && !f.tags?.includes(canon));

        await storage.saveData('revApp_literalness_v1', nextCards);
        await storage.saveData('revApp_questions_v5_react', nextQs);
        await storage.saveData('revApp_flashcards_v1', nextFs);

        return { deletedQuestions, deletedFlashcards };
    }
};

import React, { useState, useEffect, useMemo } from 'react';
import ReactDOM from 'react-dom';
import { LiteralnessCard, Question, Flashcard } from '../../types';
import { XMarkIcon, TrashIcon, ExclamationTriangleIcon } from '../icons';
import * as srs from '../../services/srsService';
import { useQuestionState } from '../../contexts/QuestionContext';
import { useFlashcardState } from '../../contexts/FlashcardContext';
import { useSettings } from '../../contexts/SettingsContext';

interface DeleteArticleModalProps {
    isOpen: boolean;
    onClose: () => void;
    card: LiteralnessCard;
    onConfirm: (card: LiteralnessCard) => void;
}

const DeleteArticleModal: React.FC<DeleteArticleModalProps> = ({ isOpen, onClose, card, onConfirm }) => {
    const [confirmText, setConfirmText] = useState('');
    const allQuestions = useQuestionState();
    const allFlashcards = useFlashcardState();
    const { settings } = useSettings();

    // Calculate Impact stats
    const stats = useMemo(() => {
        if (!isOpen) return { questions: 0, gaps: 0, flashcards: 0, pairs: 0, progress: 0 };
        const smartStats = srs.getLitRefSmartStatus(card.id, allQuestions, allFlashcards, settings);

        const qCount = smartStats.counts.total.questions;
        const gCount = smartStats.counts.total.gaps;
        const fCount = smartStats.counts.total.flashcards;
        const pCount = smartStats.counts.total.pairs;
        const reviewed = smartStats.reviewedItems;

        return {
            questions: qCount,
            gaps: gCount,
            flashcards: fCount,
            pairs: pCount,
            progress: reviewed
        };
    }, [isOpen, card, allQuestions, allFlashcards, settings]);

    if (!isOpen) return null;

    const requiredText = "DELETAR";
    const isMatch = confirmText.trim().toUpperCase() === requiredText;

    const handleConfirm = () => {
        if (isMatch) {
            onConfirm(card);
            onClose();
        }
    };

    return ReactDOM.createPortal(
        <div className="fixed inset-0 z-[10000] bg-black/80 backdrop-blur-sm flex items-center justify-center p-4 animate-fade-in" onClick={onClose}>
            <div className="bg-slate-900 border-2 border-rose-500/30 w-full max-w-md rounded-2xl shadow-2xl flex flex-col overflow-hidden" onClick={e => e.stopPropagation()}>

                <header className="p-6 border-b border-white/5 flex justify-between items-center bg-rose-950/20">
                    <div className="flex items-center gap-3">
                        <div className="p-2 bg-rose-500/10 rounded-xl text-rose-500 border border-rose-500/20">
                            <ExclamationTriangleIcon className="w-6 h-6" />
                        </div>
                        <div>
                            <h3 className="font-black text-rose-400 text-lg leading-tight uppercase tracking-tight">Excluir Lote?</h3>
                            <p className="text-[10px] text-slate-400 font-bold uppercase tracking-widest">Ação Irreversível</p>
                        </div>
                    </div>
                    <button onClick={onClose} className="p-2 text-slate-500 hover:text-white transition-colors"><XMarkIcon className="w-5 h-5"/></button>
                </header>

                <div className="p-6 space-y-6">
                    <div className="bg-white/5 p-4 rounded-xl border border-white/5 space-y-2">
                        <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Lote Selecionado</p>
                        <h4 className="text-white font-black text-xl leading-tight italic">{card.article}</h4>
                        <p className="text-xs text-sky-500 font-mono">{card.lawId} • {card.topic}</p>
                    </div>

                    <div className="space-y-3">
                        <p className="text-sm text-slate-300">
                            Esta ação apagará <strong>permanentemente</strong> o artigo e todo o conteúdo vinculado:
                        </p>

                        <div className="grid grid-cols-2 gap-2 text-xs">
                            <div className="bg-black/30 p-2 rounded flex justify-between px-3 border border-white/5">
                                <span className="text-slate-500">Questões</span>
                                <span className="text-white font-bold">{stats.questions}</span>
                            </div>
                            <div className="bg-black/30 p-2 rounded flex justify-between px-3 border border-white/5">
                                <span className="text-slate-500">Lacunas</span>
                                <span className="text-white font-bold">{stats.gaps}</span>
                            </div>
                            <div className="bg-black/30 p-2 rounded flex justify-between px-3 border border-white/5">
                                <span className="text-slate-500">Flashcards</span>
                                <span className="text-white font-bold">{stats.flashcards}</span>
                            </div>
                            <div className="bg-black/30 p-2 rounded flex justify-between px-3 border border-white/5">
                                <span className="text-slate-500">Pares</span>
                                <span className="text-white font-bold">{stats.pairs}</span>
                            </div>
                        </div>

                        {stats.progress > 0 && (
                             <div className="p-2 bg-amber-500/10 border border-amber-500/20 rounded text-amber-500 text-xs font-bold text-center">
                                 ⚠️ {stats.progress} registros de progresso serão perdidos.
                             </div>
                        )}
                    </div>

                    <div>
                        <label className="block text-xs font-bold text-slate-500 uppercase tracking-widest mb-2">
                            Digite <span className="text-white bg-white/10 px-1 rounded mx-1 select-all">{requiredText}</span> para confirmar
                        </label>
                        <input 
                            value={confirmText}
                            onChange={(e) => setConfirmText(e.target.value)}
                            className="w-full bg-slate-950 border border-white/10 rounded-xl p-3 text-white font-bold outline-none focus:border-rose-500 transition-all text-center uppercase tracking-widest placeholder-slate-700"
                            placeholder={requiredText}
                        />
                    </div>
                </div>

                <footer className="p-6 border-t border-white/5 bg-slate-950/50 flex justify-end gap-3">
                    <button onClick={onClose} className="px-5 py-3 rounded-xl text-slate-400 font-bold text-xs uppercase tracking-widest hover:text-white hover:bg-white/5 transition-colors">Cancelar</button>
                    <button 
                        onClick={handleConfirm}
                        disabled={!isMatch}
                        className={`px-8 py-3 rounded-xl font-black text-xs uppercase tracking-widest shadow-lg transition-all flex items-center gap-2 
                            ${isMatch 
                                ? 'bg-rose-600 text-white hover:bg-rose-500 shadow-rose-900/20 active:scale-95' 
                                : 'bg-slate-800 text-slate-500 cursor-not-allowed border border-white/5'}`
                        }
                    >
                        <TrashIcon className="w-4 h-4" />
                        Apagar Tudo
                    </button>
                </footer>
            </div>
        </div>,
        document.body
    );
};

