                ))}
                {lawGroups.length === 0 && (
                    <div className="col-span-full text-center py-20 text-slate-500">
                        <p className="font-bold text-lg">Nenhum núcleo de lei encontrado.</p>
                        <p className="text-sm">Importe conteúdo na aba "Importar".</p>
                    </div>
                )}
            </div>
        );
    }

